SELECT model_name
FROM display_models
WHERE manufacturer = 'Manufacturer X' AND release_date >= '2023-01-01';

SELECT recommended_brightness_nits
FROM brightness_requirements
WHERE size_id = 0 AND env_id = 0;

SELECT COUNT(model_id)
FROM display_models
WHERE size_id = 1;

SELECT development_stage
FROM product_development
WHERE model_id = 1;

SELECT manufacturer
FROM display_models
WHERE power_consumption_watts = (SELECT MAX(power_consumption_watts) FROM display_models);

SELECT AVG(brightness_nits) AS avg_brightness
FROM brightness_tests
WHERE model_id = 0 AND env_id = 1;

SELECT model_id, AVG(brightness_nits) AS average_brightness
FROM brightness_tests
GROUP BY model_id;

SELECT model_name
FROM display_models
WHERE model_id = 1;

SELECT size_range, min_size_inches
FROM screen_sizes
ORDER BY min_size_inches DESC;

SELECT size_range, min_size_inches
FROM screen_sizes
ORDER BY size_id ASC;
